insert into public.lunch_restaurants (name,category,menu,price,rating,walk,exit,note) values
  ('청목', 'han', '가정식 백반정식', 10000, 4.2, '6번출구 도보 5분 · 약 360m', '6', '강남 직장인 단골 백반. 반찬이 정갈하고 된장찌개·수육이 깔끔, 식후 숭늉까지 챙겨줍니다.'),
  ('토담골', 'han', '오겹살 점심정식', 8000, 4.3, '6번출구 도보 4분 · 약 250m', '6', '보리밥에 청국장이 메인. 8,000원 오겹살정식이 가성비 끝판왕, 고등어조림·구이김까지 한상.'),
  ('서진식당', 'han', '제육김치찜·스팸정식', 9000, 4.3, '6번출구 도보 5분 · 약 330m', '6', '맵고 짭짤한 한식이 강점. 안 매운 날엔 스팸정식 추천. 회전 빨라 점심에 후딱 먹기 좋아요.'),
  ('딸부자네 불백', 'han', '불고기 백반', 9000, 4.1, '6번출구 도보 7분 · 약 450m', '6', '양 많고 집밥 느낌. 매운 제육·낙지볶음도 인기. 김치 리필 무료로 든든하게.'),
  ('뉴욕김치찌개', 'han', '치즈 김치찌개', 9000, 4, '6번출구 도보 3분 · 약 160m', '6', '점심마다 줄 서는 김치찌개 맛집. 라면사리·치즈오믈렛 추가가 국룰. 자리는 좁은 편.'),
  ('1992 덮밥&짜글이 강남점', 'han', '제육덮밥 / 짜글이', 9000, 4.8, '6번출구 도보 4분 · 약 265m', '6', '한옥풍 인테리어에 키오스크 주문. 덮밥·짜글이 가성비 좋고 혼밥·외국인 다 편한 곳.'),
  ('노랑저고리', 'han', '해물 가정식 점심', 11000, 4.5, '5번출구 도보 3분 · 약 210m', '5', '서초동 인기 한식. 멍게비빔밥·해물요리가 강점, 분위기 아늑하고 직원 친절. 1,300+ 리뷰의 검증된 곳.'),
  ('영진식당', 'han', '점심 백반 (자율 뷔페)', 5500, 4.1, '4번출구 도보 7분 · 약 500m', '4', '5,500원 점심 백반에 반찬 뷔페 무한. 메인은 매일 바뀜. 지하 주차장 쪽이라 입구 주의, 가성비 끝판.'),
  ('딸부자네 불백 서초점', 'han', '불고기 백반 / 매운제육', 9000, 4.3, '4·5번출구 도보 1분 · 약 60m', '4', '강남대로 서편 24시 불백집. 주문 즉시 깻잎·된장국·쌈채 한상. 매운제육 불고기 인기, 가성비 최고.'),
  ('국밥생각 강남역점', 'guk', '돼지국밥', 10000, 4.9, '6번출구 도보 4분 · 약 245m', '6', '24시간 국밥집. 고기 푸짐하고 깍두기·파김치 셀프 무한. 깔끔한 한 끼로 딱.'),
  ('순대생각 강남본점', 'guk', '순대국밥', 9000, 3.8, '6번출구 도보 6분 · 약 360m', '6', '건더기가 국물보다 많은 푸짐한 순대국. 양 많기로 유명, 다대기로 간 맞춰 드세요.'),
  ('농민백암순대', 'guk', '순대국밥', 9000, 4.6, '6번출구 도보 8분 · 약 500m', '6', '강남 순대국 명물. 점심 웨이팅 있는 편이지만 회전 빠름. 혼밥도 환영.'),
  ('강남진해장', 'guk', '내장탕·해장국', 11000, 4.2, '6번출구 도보 3분 · 약 180m', '6', '강남역 보기 드문 24시 해장국집. 진한 국물에 양 푸짐. 전날 과음했다면 여기로.'),
  ('제주은희네해장국 강남역점', 'guk', '소고기 해장국', 11000, 4.3, '6번출구 도보 6분 · 약 360m', '6', '맑은 소고기 해장국. 콩나물·선지 듬뿍, 속 풀리는 한 그릇.'),
  ('국밥쟁이 강남역점', 'guk', '순대·수육국밥', 9000, 3.9, '4번출구 도보 2분 · 약 130m', '4', '강남대로 서편 24시 국밥집. 태블릿 주문·즉시 결제로 회전 빠름. 늦은 점심·해장에 든든.'),
  ('청담돈가스', 'don', '돈까스 정식 (매운갈비찜·고등어)', 9000, 4.1, '6번출구 도보 7분 · 약 430m', '6', '가성비 돈까스 맛집. 점심엔 직장인 웨이팅 있지만 회전 빠름. 매운갈비찜·고등어구이 곁들임 인기.'),
  ('야기카레', 'don', '소고기 카레 / 카레우동', 8500, 4.5, '6번출구 도보 3분 · 약 175m', '6', '오래 끓인 정통 일본식 카레. 다진 소고기 듬뿍, 밥·파 무한리필에 1만원 이하. 빌딩 지하 2층.'),
  ('오레노라멘 강남', 'ram', '닭육수 라멘 (소바/스파이시)', 10000, 4.8, '6번출구 도보 4분 · 약 225m', '6', '국물·면 리필 가능한 인기 라멘. 메뉴 단순해 퀄리티 집중, 혼밥 성지.'),
  ('산쇼쿠라멘 강남본점', 'ram', '토리파이탄 라멘', 10000, 4.8, '6번출구 도보 5분 · 약 310m', '6', '진하면서 느끼하지 않은 닭육수. 차슈 부드럽고 레몬 무절임이 포인트, 혼밥 편한 분위기.'),
  ('멘노아게', 'ram', '라멘 (스파이시/논스파이시)', 10000, 4.4, '6번출구 도보 4분 · 약 220m', '6', '국물 평이 좋은 라멘집. 빠른 서빙과 친절한 응대. 가성비 라멘으로 점심에 좋아요.'),
  ('사가라멘', 'ram', '차슈라멘 + 만두', 9000, 4, '4·6번출구 도보 2분 · 약 125m', '4', '강남역 코앞. 1인 부스석에서 태블릿 주문, 마늘국물 인기. 빠른 한 끼.'),
  ('와쇼이켄', 'ram', '돈코츠 라멘', 11000, 4.3, '6번출구 도보 7분 · 약 450m', '6', '진한 국물의 정통 라멘. 가라아게도 인기. 점심 피크엔 살짝 붐벼요.'),
  ('무궁화반점 강남점', 'chi', '짜장·짬뽕·덮밥', 8000, 4.8, '6번출구 도보 2분 · 약 80m', '6', '24시간 중화요리. 계란프라이·공깃밥 무한 서비스에 가격 착함. 6번출구 바로 앞 가성비 중식.'),
  ('남소관 우육도삭면', 'chi', '우육도삭면 / 큐민비프', 11000, 4.6, '6번출구 도보 2분 · 약 120m', '6', '대만식 칼국수(도삭면)와 딤섬. 큐민비프 인기, 가격 합리적이고 분위기도 좋아요. 안 매운 것도 약간 매움 주의.'),
  ('신복면관', 'chi', '어향가지덮밥 / 우육도삭면', 10000, 4.8, '6번출구 도보 3분 · 약 175m', '6', '사천식 수타면 + 홍콩식 딤섬. 어향가지덮밥·소룡포 강추, 태블릿 주문에 서빙 빠름.'),
  ('Chasyuming', 'chi', '짬뽕·탕수육', 9000, 4.5, '6번출구 도보 3분 · 약 170m', '6', '테이블 칸막이 있는 깔끔한 지하 중식당. 면발 쫄깃하고 가격 합리적, 가족·단체도 OK.'),
  ('강남수향', 'chi', '마파두부밥 / 상하이 딤섬', 10000, 4.7, '6번출구 도보 6분 · 약 390m', '6', '중국인이 직접 하는 상하이식. 생전만두(셩지엔)·소룡포가 시그니처, 마파두부밥 10,000원.'),
  ('꾸아 강남역CGV점', 'viet', '소고기 쌀국수', 10000, 4.9, '6번출구 도보 6분 · 약 390m', '6', '아이패드 주문, 5분 만에 김 나는 쌀국수. 갈비 쌀국수는 하루 10그릇 한정. 일찍 가세요.'),
  ('Tamtam', 'viet', '양지/내장 쌀국수', 11000, 4.1, '6번출구 도보 4분 · 약 215m', '6', '늘 붐비는 인기 베트남식. 양지·내장 쌀국수 양 푸짐, 매콤한 분짜·튀김도 인기.'),
  ('An-An 강남', 'viet', '쌀국수 / 분짜·반쎄오', 10000, 4.4, '6번출구 도보 4분 · 약 230m', '6', '민트톤 인테리어의 넓고 깔끔한 베트남식. 채소 듬뿍 짜조, 부드러운 면발. QR 주문.'),
  ('Baba India', 'viet', '런치 세트 (커리+난)', 12000, 4.3, '6번출구 도보 8분 · 약 530m', '6', '강남 인근 인도 음식 평이 좋은 곳. 점심 런치세트는 양 넉넉하고 난 신선, 샐러드·수프 사이드 제공.'),
  ('베트남이랑', 'viet', '소고기 쌀국수 / 분짜', 11000, 4.3, '4번출구 도보 1분 · 약 70m', '4', '강남대로 서편 베트남 스트리트푸드. 분짜·라이스페이퍼 인기, 베트남 음악에 분위기 살아있음. 500+ 리뷰.'),
  ('장원김밥', 'kim', '김밥 + 라면 / 떡국', 6500, 4.3, '6번출구 도보 5분 · 약 300m', '6', '현지인 많은 분식 노포. 영어 메뉴 있고 가격 착함. 아침 8시부터 열어 든든한 한 끼.'),
  ('김가네 강남역점', 'kim', '김밥·분식 세트', 5000, 3.6, '6번출구 도보 4분 · 약 220m', '6', '이모님들 친절한 동네 김밥집. 마늘김 김밥이 편안한 맛. 혼자 후딱 먹기 좋아요.'),
  ('싸다김밥 강남역점', 'kim', '김밥 + 떡볶이', 6000, 3.9, '6번출구 도보 3분 · 약 195m', '6', '24시간 운영. 메뉴 다양하고 양 넉넉. 유부김밥·떡볶이 조합 추천.'),
  ('로봇김밥 강남역점', 'kim', '김밥 + 라면', 6000, 3.5, '6번출구 도보 3분 · 약 195m', '6', '강남역 지하상가에 위치. 와사비참치김밥 인기, 터치오더로 빠르게.'),
  ('Gimbap Cafe', 'kim', '즉석 김밥', 5000, 3.4, '6번출구 도보 5분 · 약 320m', '6', '갓 싼 김밥이 신선하고 저렴. 빠르고 깔끔, 바쁜 날 테이크아웃으로 딱.'),
  ('고봉민김밥인 강남아르누보점', 'kim', '김밥 + 떡볶이', 6000, 4.3, '4번출구 도보 7분 · 약 470m', '4', '강남대로 서편 코너 분식. 속 알찬 김밥에 떡볶이 조합 인기, 사장님 친절하고 채식 옵션도 대응.'),
  ('Cry Cheeseburger 강남', 'burg', '치즈버거 세트', 8000, 4.9, '6번출구 도보 6분 · 약 400m', '6', '가성비 좋은 수제버거. 패티 육즙 좋고 감자튀김 강추, 케첩 셀프. 활기찬 분위기.'),
  ('힘난다버거 강남역점', 'burg', '힘난다 치즈버거 세트', 9000, 4.2, '6번출구 도보 4분 · 약 257m', '6', '버터향 번에 두툼한 패티. 새우버거·버섯치즈버거도 인기. 매장 작아 테이크아웃 많음.'),
  ('올라포케 강남점', 'salad', '연어 포케볼', 12000, 5, '6번출구 도보 7분 · 약 430m', '6', '밥·채소 비율 조절 가능한 포케. 연어 큼직, 토핑 다양해 가볍지만 든든. 혼밥 좌석 넉넉.'),
  ('PROTEINER 강남역점', 'salad', '닭가슴살 박스 (M)', 8900, 4.8, '6번출구 도보 7분 · 약 430m', '6', '저당·고단백 다이어트 식단. 닭가슴살 박스·파스타 인기, 올리브김치볶음 추가 추천. 아침 8시 반 오픈.'),
  ('봉된장', 'han', '강된장 보리밥 / 된장찌개', 9000, 4.1, '6번출구 도보 6분', '6', '콩알 씹히는 진한 강된장이 시그니처. 작지만 빠른 한 끼로 좋은 가정식 노포.'),
  ('미진식당', 'han', '오징어덮밥 / 제육·순두부', 8000, 4.5, '5번출구 도보 4분', '5', '미진프라자 지하의 숨은 백반 맛집. 오징어덮밥·보쌈 가성비 좋아 점심 웨이팅.'),
  ('오봉집 강남역점', 'han', '낙지볶음 + 보쌈정식', 11000, 4.5, '6번출구 도보 6분', '6', '숯불향 낙지볶음에 보쌈·막국수까지. 든든한 한상, 가족·회식도 OK.'),
  ('851복덮밥 강남본점', 'han', '연어덮밥 / 육회비빔밥', 11000, 4.6, '6번출구 도보 6분', '6', '연어·육회 덮밥이 인기(조기 품절). 반찬 푸짐, 가성비 덮밥 전문.'),
  ('바른고기 정육점식당 강남점', 'han', '한우 점심 불고기정식', 12000, 4.2, '6번출구 도보 3분', '6', '숙성 한우를 합리적으로. 점심 불고기·덮밥 메뉴 가성비, 밥 추천.'),
  ('돌깨마을 뭇돌순두부 강남역점', 'guk', '순두부찌개', 8500, 3.8, '6번출구 도보 3분', '6', '빌딩 지하의 순두부 전문. 반찬 넉넉하고 가성비, 아침부터 영업.'),
